const fs = require('fs');
let lines = [];
try { lines = fs.readFileSync('/config/energy-sources.txt','utf8').split(/\r?\n/); } catch (e) {}
const urls = lines.map(function(l){ return l.trim(); }).filter(function(l){ return l && l.charAt(0) !== '#'; });
if (!urls.length) { return [{ json: { url: '' } }]; }
return urls.map(function(u){ return { json: { url: u } }; });

const items = $input.all();
const arts = items.map(function(i){ return i.json; }).filter(function(a){ return a && (a.title || a.contentSnippet || a.content); });
const lines = arts.slice(0,15).map(function(a){
  var t = (a.title||'').toString();
  var s = (a.contentSnippet||a.content||'').toString().replace(/\s+/g,' ').slice(0,160);
  var u = (a.link||a.url||'').toString();
  return '- ' + t + ' — ' + s + ' (' + u + ')';
});
const text = lines.length ? lines.join('\n') : 'No source articles were retrieved today.';
return [{ json: { articles: text, count: arts.length, date: new Date().toISOString().slice(0,10) } }];

