const md = ($json && $json.message && $json.message.content) ? $json.message.content : '';
const top = md.split(/\n/).filter(function(l){ return /adnoc|energy|oil|gas|lng|masdar|taqa/i.test(l); }).slice(0,4).join('; ') || 'UAE and ADNOC energy sector developments';
const style = 'Premium editorial intelligence-report cover. Deep navy (#0A1A2F) background with refined gold (#C9A24B) accents. Abstract professional energy motifs (flowing light, geometric grids, subtle infrastructure silhouettes). NO text, NO logos, NO faces. Cinematic, restrained, high-end consultancy aesthetic.';
return [{ json: { markdown: md || 'No data available for this period.', date: new Date().toISOString().slice(0,10), coverPrompt: style + ' Visual theme inspired by: ' + top } }];

const md = ($json && $json.markdown) || 'No data available for this period.';
const date = ($json && $json.date) || new Date().toISOString().slice(0,10);
let coverUrl = '';
try { coverUrl = $('Generate Cover (Image Provider)').first().json.data[0].url || ''; } catch (e) { coverUrl = ''; }
const esc = md.replace(/[&<>]/g, function(c){ return ({ '&':'&amp;', '<':'&lt;', '>':'&gt;' })[c]; });
const img = coverUrl ? ('<img src=\"' + coverUrl + '\" style=\"width:100%;max-height:280px;object-fit:cover\"/>') : '';
const html = '<!doctype html><meta charset=\"utf-8\"><title>Daily Energy Intelligence Brief — ' + date + '</title>' +
  '<div style=\"font-family:Georgia,serif;color:#11151c\">' +
  '<div style=\"background:#0A1A2F;color:#E7C76A;padding:18px;font-size:18px\">JARVIS INTELLIGENCE — Daily Energy Intelligence Brief — ' + date + '</div>' +
  img +
  '<div style=\"padding:18px\"><pre style=\"white-space:pre-wrap;font-family:inherit;font-size:15px;line-height:1.55\">' + esc + '</pre></div></div>';
return [{ json: { date: date, html: html, markdown: md } }];

const fs = require('fs');
const date = $json.date;
const html = $json.html;
const dirs = ['/reports/energy-intelligence', '/reports/archive/energy-intelligence'];
for (var k = 0; k < dirs.length; k++) {
  try { fs.mkdirSync(dirs[k], { recursive: true }); fs.writeFileSync(dirs[k] + '/energy-intelligence-' + date + '.html', html); } catch (e) {}
}
try { fs.writeFileSync('/logs/last-run-success.txt', new Date().toISOString() + ' energy-intelligence'); } catch (e) {}
return [{ json: $json }];
